const raw = $('Webhook').first().json.body || {};
const enhanced = $input.first().json.message?.content || raw.prompt || 'a cinematic scene';
const channelId = raw.channel || raw.channel_id || 'C0AKJ788GJK';
const userId    = raw.user_id || raw.user    || '';
const clientId  = 'n8n-vid-' + Date.now();
const seed = Math.floor(Math.random() * 1_000_000_000);

// AnimateDiff-Evolved + SDXL ComfyUI workflow
const workflow = {
  "1": { "inputs": {"ckpt_name": "sd_xl_base_1.0.safetensors"}, "class_type": "CheckpointLoaderSimple" },
  "2": { "inputs": {"text": enhanced, "clip": ["1",1]}, "class_type": "CLIPTextEncode" },
  "3": { "inputs": {"text": "blurry, low quality, distorted, watermark, static, frozen", "clip": ["1",1]}, "class_type": "CLIPTextEncode" },
  "4": {
    "inputs": {
      "model": ["1",0],
      "model_name": "v3_sd15_mm.ckpt",
      "beta_schedule": "sqrt_linear (AnimateDiff)",
      "motion_scale": 1.0,
      "apply_v2_models_properly": True
    },
    "class_type": "ADE_AnimateDiffLoaderWithContext"
  },
  "5": {
    "inputs": {
      "seed": seed, "steps": 20, "cfg": 7.5,
      "sampler_name": "euler_ancestral", "scheduler": "karras", "denoise": 1.0,
      "model": ["4",0], "positive": ["2",0], "negative": ["3",0], "latent_image": ["6",0]
    },
    "class_type": "KSampler"
  },
  "6": { "inputs": {"width": 768, "height": 512, "batch_size": 16}, "class_type": "EmptyLatentImage" },
  "7": { "inputs": {"samples": ["5",0], "vae": ["1",2]}, "class_type": "VAEDecode" },
  "8": {
    "inputs": {
      "frame_rate": 8, "loop_count": 0,
      "filename_prefix": "n8n_video",
      "format": "image/gif",
      "pingpong": False, "save_output": True,
      "images": ["7",0]
    },
    "class_type": "VHS_VideoCombine"
  }
};

return [{ json: { workflow, clientId, channelId, userId, prompt: enhanced } }];

const promptId  = $input.first().json.prompt_id;
const buildData = $('Build ComfyUI Payload').first().json;
const maxTries  = 90;   // 7.5 min — video takes longer

for (let i = 0; i < maxTries; i++) {
  await new Promise(r => setTimeout(r, 5000));
  const history = await $helpers.httpRequest({
    method: 'GET',
    url: `http://host.docker.internal:8188/history/${promptId}`
  });
  const entry = history[promptId];
  if (entry?.status?.completed) {
    // VHS_VideoCombine outputs gifs/videos
    const outputs = entry.outputs || {};
    for (const nodeOut of Object.values(outputs)) {
      if (nodeOut.gifs?.length) {
        const vid = nodeOut.gifs[0];
        return [{ json: {
          promptId,
          filename:  vid.filename,
          subfolder: vid.subfolder || '',
          type:      vid.type || 'output',
          channelId: buildData.channelId,
          userId:    buildData.userId,
          prompt:    buildData.prompt
        }}];
      }
    }
  }
}
throw new Error('ComfyUI video generation timed out');
